}

return [{
  json: {
    ...$json,
    account_key: m.account_key,
    channel_platform_id: m.channel_platform_id,
  }
}];

// Explode LINE body.events[] -> 1 item per event
const req = $json;
const body = req.body ?? req;
const events = Array.isArray(body?.events) ? body.events : [];

return events.map((event) => {
  const event_type = String(event?.type || '').toLowerCase();
  const line_user_id = event?.source?.userId || null;
  const reply_token = event?.replyToken || "";

  // Rich menu can be:
  // - message(text) via "message" action
  // - postback via "postback" action
  const text =
    (event?.message?.type === 'text')
      ? String(event?.message?.text || '').trim()
      : '';

  const postback_data = (event_type === 'postback')
    ? String(event?.postback?.data || '').trim()
    : '';

  const cmd = String(postback_data || text || '').trim();

  return {
    json: {
      account_key: req.account_key,
      channel_platform_id: req.channel_platform_id,
      event_type,
      line_user_id,
      reply_token,
      text,
      postback_data,
      cmd,
      ts: event?.timestamp || null,
      raw_event: {
        type: event?.type,
        mode: event?.mode,
        source: event?.source,
        timestamp: event?.timestamp,
        message: event?.message,
        postback: event?.postback,
