  return { type: "text", text: `📅 จองคิวออนไลน์ได้ที่นี่ครับ\n${link}` };
}

function askAiIntro() {
  return {
    type: "text",
    text: "สวัสดีครับ 👋\nสอบถามเบื้องต้นได้เลย เช่น ราคา / พื้นที่บริการ / รับซ่อมไหม / ค่าตรวจเช็ค/ประเมินหน้างานเท่าไร\nค่าตรวจเช็ค/ประเมินหน้างาน เริ่มต้น 1,000 บาท กรณีเช็กแล้วไม่ซ่อม\nถ้าต้องการจองคิว ประเมินหน้างาน หรือตามงาน ผมจะส่งต่อแอดมินให้ครับ"
  };
}

// ✅ IMPORTANT: compute once, return once, always carry context
let route = "IGNORE";
