  return [{ json: { ...$json, route, replyPayload, pushPayload, cmd } }];
}

if (cmd === "MENU:PRICE_CLEAN") {
  route = "PRICE_SHOW";

  // ✅ ข้อความประกาศปรับราคา
  const announcementText = {
    type: "text",
    text: "📢 ประกาศแจ้งปรับราคาบริการล้างแอร์\nเนื่องจากต้นทุนในการเดินทางและการให้บริการปรับตัวสูงขึ้น ทางบริษัทขอแจ้งปรับราคาเริ่มต้นของบริการล้างแอร์ ดังนี้"
