    text: "หลังดูราคาแล้ว ถ้าต้องการสอบถามเบื้องต้น พิมพ์ถามได้เลย หรือกด “ติดต่อแอดมิน” ได้ทันทีค่ะ\nค่าตรวจเช็ค/ประเมินหน้างาน เริ่มต้น 1,000 บาท กรณีเช็คแล้วไม่ซ่อม"
  };

  // ส่ง array ที่มีทั้ง [ประกาศ, FlexMessage, ข้อความ]
  replyPayload = { replyToken, messages: [announcementText, genPriceFlex(), followUpText] };

} else if (cmd === "MENU:BOOK") {
  route = "BOOK";
  replyPayload = { replyToken, messages: [bookMsg()] };
} else if (cmd === "MENU:ASK_AI") {
