  const m = cmd.match(/^ADMIN:(TRACK|ISSUE|OTHER)$/);
  if (m) {
    route = "ADMIN_PUSH";
    const reasonMap = { TRACK: "ติดตามงาน", ISSUE: "แจ้งปัญหา", OTHER: "อื่นๆ" };
    const reason = reasonMap[m[1]] || m[1];

    replyPayload = { replyToken, messages: [adminAck(reason)] };

    const adminTo = String($json.ADMIN_TO || "").trim();
    if (adminTo) {
      const who = String($json.line_user_id || $json.platform_user_id || "unknown");
