// Detect if plain text message looks like a question
const text = String($json.text || '').trim();
if (!text) return [{ json: { ...$json, isQuestion: false } }];

// Simple heuristics for Thai questions
const questionPatterns = [
  /\?/,                          // has question mark
  /^ราคา/,                        // starts with ราคา
  /ราคาเท่าไร|ราคาเท่าไหร่/,
  /เท่าไร|เท่าไหร่/,
  /ได้ไหม|ได้มั้ย|ได้มั้ยค/,
  /มั้ย|ไหม/,
  /ยังไง|อย่างไร/,
  /เมื่อไร|เมื่อไหร่|วันไหน/,
  /กี่วัน|กี่ชั่วโมง|กี่โมง/,
  /ทำไม|เพราะอะไร/,
  /มีไหม|มีมั้ย/,
  /รับไหม|รับมั้ย/,
  /บริการ.*ไหม|บริการ.*มั้ย/,
  /ซ่อม|ติดตั้ง|ล้าง|เติมน้ำยา/,
  /แอร์.*เสีย|แอร์.*ไม่/,
  /ไม่เย็น|ไม่ทำงาน|ไม่ติด/,
  /how|what|when|where|why|which|can you|do you/i,
];

const isQuestion = questionPatterns.some(p => p.test(text));
return [{ json: { ...$json, isQuestion } }];

